export declare const STORY_CSS = "\n    #s-wrapped, #s-personas, #s-chapters, #s-calendar { scroll-margin-top: 76px; }\n    .story-headline {\n      margin: 0 0 14px;\n      font-size: clamp(17px, 2.5vw, 21px);\n      line-height: 1.55;\n      font-weight: 650;\n      color: var(--ink);\n      max-width: 48ch;\n    }\n    .wrapped-section { margin-bottom: 20px; }\n    .wrapped-section h2 { margin: 0 0 6px; font-size: 20px; font-weight: 800; letter-spacing: -0.02em; }\n    .wrapped-lede { margin: 0 0 14px; font-size: 13px; color: var(--muted); line-height: 1.5; }\n    .wrapped-deck {\n      display: grid;\n      gap: 12px;\n      grid-template-columns: repeat(auto-fill, minmax(min(100%, 220px), 1fr));\n      padding: 0;\n    }\n    .wrapped-card {\n      border-radius: 18px;\n      border: 1px solid var(--line);\n      padding: 22px 20px;\n      min-height: 200px;\n      display: flex;\n      flex-direction: column;\n      justify-content: flex-end;\n      background: linear-gradient(155deg, rgba(15, 107, 92, 0.14), rgba(196, 92, 42, 0.08));\n      box-shadow: var(--shadow);\n      position: relative;\n      overflow: hidden;\n    }\n    .wrapped-card::before {\n      content: attr(data-emoji);\n      position: absolute;\n      top: 12px;\n      right: 14px;\n      font-size: 2.4rem;\n      opacity: 0.35;\n      line-height: 1;\n    }\n    .wrapped-card-kicker {\n      font-size: 11px;\n      font-weight: 800;\n      letter-spacing: 0.06em;\n      text-transform: uppercase;\n      color: var(--muted);\n      margin: 0 0 6px;\n    }\n    .wrapped-card-stat {\n      margin: 0;\n      font-size: clamp(32px, 6vw, 44px);\n      font-weight: 900;\n      letter-spacing: -0.04em;\n      line-height: 1.05;\n      color: var(--ink);\n      word-break: break-word;\n    }\n    .wrapped-card-sub {\n      margin: 10px 0 0;\n      font-size: 13px;\n      line-height: 1.5;\n      color: var(--muted);\n    }\n    .persona-grid {\n      display: grid;\n      gap: 10px;\n      grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));\n    }\n    .persona-chip {\n      padding: 12px 14px;\n      border-radius: 12px;\n      border: 1px solid var(--line);\n      background: var(--panel);\n    }\n    .persona-chip strong {\n      display: block;\n      font-size: 14px;\n      color: var(--ink);\n      margin-bottom: 4px;\n    }\n    .persona-chip em {\n      display: block;\n      font-style: normal;\n      font-size: 12px;\n      font-weight: 800;\n      color: var(--accent);\n      margin-bottom: 4px;\n    }\n    .persona-chip span { font-size: 11px; color: var(--muted); line-height: 1.4; }\n    .chapter-list { display: grid; gap: 10px; margin: 0; padding: 0; list-style: none; }\n    .chapter-item {\n      display: grid;\n      grid-template-columns: auto 1fr auto;\n      gap: 10px 14px;\n      align-items: center;\n      padding: 14px 16px;\n      border-radius: 12px;\n      border: 1px solid var(--line);\n      background: var(--panel);\n    }\n    @media (max-width: 560px) {\n      .chapter-item { grid-template-columns: auto 1fr; }\n      .chapter-item .chapter-stat { grid-column: 1 / -1; text-align: left; }\n    }\n    .chapter-badge {\n      font-size: 12px;\n      font-weight: 900;\n      color: var(--accent);\n      min-width: 2.5rem;\n    }\n    .chapter-meta { font-size: 13px; line-height: 1.45; color: var(--ink); }\n    .chapter-meta small { display: block; color: var(--muted); font-size: 11px; margin-top: 4px; }\n    .chapter-stat { text-align: right; font-size: 13px; font-weight: 750; color: var(--muted); font-variant-numeric: tabular-nums; }\n\n    /* GitHub contribution graph (\uC794\uB514) */\n    :root {\n      --gh-cell-size: 11px;\n      --gh-cell-gap: 3px;\n      --gh-cell-0: #ebedf0;\n      --gh-cell-1: #9be9a8;\n      --gh-cell-2: #40c463;\n      --gh-cell-3: #30a14e;\n      --gh-cell-4: #216e39;\n    }\n    @media (prefers-color-scheme: dark) {\n      :root:not([data-theme=\"light\"]) {\n        --gh-cell-0: #161b22;\n        --gh-cell-1: #0e4429;\n        --gh-cell-2: #006d32;\n        --gh-cell-3: #26a641;\n        --gh-cell-4: #39d353;\n      }\n    }\n    :root[data-theme=\"dark\"] {\n      --gh-cell-0: #161b22;\n      --gh-cell-1: #0e4429;\n      --gh-cell-2: #006d32;\n      --gh-cell-3: #26a641;\n      --gh-cell-4: #39d353;\n    }\n    :root[data-theme=\"light\"] {\n      --gh-cell-0: #ebedf0;\n      --gh-cell-1: #9be9a8;\n      --gh-cell-2: #40c463;\n      --gh-cell-3: #30a14e;\n      --gh-cell-4: #216e39;\n    }\n    .gh-contrib {\n      border: 1px solid var(--line);\n      border-radius: 12px;\n      padding: 16px 18px 14px;\n      background: var(--panel);\n    }\n    .gh-contrib-summary {\n      margin: 0 0 12px;\n      font-size: 14px;\n      line-height: 1.4;\n      color: var(--muted);\n    }\n    .gh-contrib-summary strong {\n      font-weight: 600;\n      color: var(--ink);\n      font-variant-numeric: tabular-nums;\n    }\n    .gh-contrib-span {\n      display: block;\n      margin-top: 4px;\n      font-size: 11px;\n      color: var(--muted);\n    }\n    .gh-cal-scroll {\n      overflow-x: auto;\n      overflow-y: hidden;\n      max-width: 100%;\n      -webkit-overflow-scrolling: touch;\n      padding-bottom: 2px;\n    }\n    .gh-cal-graph {\n      display: grid;\n      grid-template-areas:\n        \". months\"\n        \"days weeks\";\n      grid-template-columns: max-content max-content;\n      column-gap: 8px;\n      row-gap: 4px;\n      width: max-content;\n      min-width: min(100%, max-content);\n    }\n    .gh-cal-days {\n      grid-area: days;\n      display: grid;\n      grid-template-rows: repeat(7, var(--gh-cell-size));\n      gap: var(--gh-cell-gap);\n      align-items: center;\n      font-family: ui-sans-serif, system-ui, -apple-system, \"Segoe UI\", Helvetica, Arial, sans-serif;\n      font-size: 9px;\n      line-height: 1;\n      color: var(--muted);\n      padding-right: 2px;\n    }\n    .gh-cal-days span {\n      height: var(--gh-cell-size);\n      display: flex;\n      align-items: center;\n    }\n    .gh-cal-days span:empty { visibility: hidden; }\n    .gh-cal-months {\n      grid-area: months;\n      display: grid;\n      grid-template-columns: repeat(var(--gh-weeks), var(--gh-cell-size));\n      gap: var(--gh-cell-gap);\n      height: 14px;\n      align-items: end;\n      font-family: ui-sans-serif, system-ui, -apple-system, \"Segoe UI\", Helvetica, Arial, sans-serif;\n      font-size: 9px;\n      line-height: 1;\n      color: var(--muted);\n    }\n    .gh-cal-month {\n      grid-column: span 1;\n      white-space: nowrap;\n      overflow: visible;\n    }\n    .gh-cal-weeks {\n      grid-area: weeks;\n      display: grid;\n      grid-template-columns: repeat(var(--gh-weeks), var(--gh-cell-size));\n      grid-template-rows: repeat(7, var(--gh-cell-size));\n      gap: var(--gh-cell-gap);\n      grid-auto-flow: column;\n    }\n    .gh-cal-cell {\n      width: var(--gh-cell-size);\n      height: var(--gh-cell-size);\n      border-radius: 2px;\n      background: var(--gh-cell-0);\n      display: block;\n    }\n    .gh-cal-cell[data-level=\"1\"] { background: var(--gh-cell-1); }\n    .gh-cal-cell[data-level=\"2\"] { background: var(--gh-cell-2); }\n    .gh-cal-cell[data-level=\"3\"] { background: var(--gh-cell-3); }\n    .gh-cal-cell[data-level=\"4\"] { background: var(--gh-cell-4); }\n    .gh-cal-cell[data-level=\"0\"] { background: var(--gh-cell-0); border: 1px solid color-mix(in srgb, var(--line) 70%, transparent); }\n    .gh-cal-legend {\n      display: flex;\n      align-items: center;\n      justify-content: flex-end;\n      gap: 4px;\n      margin-top: 12px;\n      font-family: ui-sans-serif, system-ui, -apple-system, \"Segoe UI\", Helvetica, Arial, sans-serif;\n      font-size: 11px;\n      color: var(--muted);\n    }\n    .gh-cal-legend-scale {\n      display: inline-flex;\n      gap: var(--gh-cell-gap);\n      align-items: center;\n      margin: 0 2px;\n    }\n    .gh-cal-legend-scale i {\n      width: var(--gh-cell-size);\n      height: var(--gh-cell-size);\n      border-radius: 2px;\n      display: block;\n      font-style: normal;\n      background: var(--gh-cell-0);\n    }\n    .gh-cal-legend-scale i[data-level=\"1\"] { background: var(--gh-cell-1); }\n    .gh-cal-legend-scale i[data-level=\"2\"] { background: var(--gh-cell-2); }\n    .gh-cal-legend-scale i[data-level=\"3\"] { background: var(--gh-cell-3); }\n    .gh-cal-legend-scale i[data-level=\"4\"] { background: var(--gh-cell-4); }\n\n";
